116	// =============================================================================
117	// Signature lookup
118	// =============================================================================
119	
120	/// Index of irreducible function symbols by (name, arity).  Mirrors
121	/// `irreducibleFunSyms maudeSig` membership tests.
122	struct Irreducible {
123	    /// Arities (keyed by name-bytes) of every irreducible NoEq symbol.
124	    noeq: BTreeMap<Vec<u8>, BTreeSet<usize>>,
125	    /// Irreducible AC symbols (e.g. `Mult`, `NatPlus` are irreducible; `Xor`
126	    /// is reducible).  HS keys on the `FunSym` value, which for AC ops is
127	    /// `AC <ACSym>`.
128	    ac: BTreeSet<AcSym>,
129	    /// Names of all nullary NoEq symbols in the FULL signature.  Used to
130	    /// resolve a bare `Var` whose name is a declared nullary funsym into an
131	    /// application (mirrors HS resolving `f/0` to `FApp f []`).
132	    nullary_names: BTreeSet<Vec<u8>>,
133	}
134	
135	impl Irreducible {
136	    fn from_sig(sig: &MaudeSig) -> Self {
137	        let mut noeq: BTreeMap<Vec<u8>, BTreeSet<usize>> = BTreeMap::new();
138	        let mut ac = BTreeSet::new();
139	        for s in &sig.irreducible_fun_syms {
140	            match s {
141	                FunSym::NoEq(n) => {
142	                    noeq.entry(n.name.to_vec()).or_default().insert(n.arity);
143	                }
144	                FunSym::Ac(a) => {
145	                    ac.insert(*a);
146	                }
147	                _ => {}
148	            }
149	        }
150	        let mut nullary_names = BTreeSet::new();
151	        for s in sig.fun_syms.iter() {
152	            if let FunSym::NoEq(n) = s {
153	                if n.arity == 0 {
154	                    nullary_names.insert(n.name.to_vec());
155	                }
156	            }
157	        }
158	        Irreducible { noeq, ac, nullary_names }
159	    }
160	
161	    /// Is the NoEq symbol `name/arity` irreducible?
162	    fn is_irreducible(&self, name: &str, arity: usize) -> bool {
163	        self.noeq.get(name.as_bytes()).is_some_and(|s| s.contains(&arity))
164	    }
165	
166	    /// Is the AC symbol `a` irreducible?
167	    fn is_ac_irreducible(&self, a: AcSym) -> bool {
168	        self.ac.contains(&a)
169	    }
170	
171	    /// Is `name` a declared nullary funsym?
172	    fn nullary_named(&self, name: &str) -> bool {
173	        self.nullary_names.contains(name.as_bytes())
174	    }
175	}
