181	/// Port of HS `formulaReports`'s `checkTerms` arm (Wellformedness.hs:1003),
182	/// for every lemma + restriction formula (in theory order, lemmas before
183	/// restrictions — HS `annFormulas`).  Macros must already be expanded by
184	/// the caller (HS applies `applyMacroInFormula` first).
185	pub fn check_terms_wf(thy: &p::Theory, sig: &MaudeSig) -> Vec<WfError> {
186	    let irr = Irreducible::from_sig(sig);
187	    let mut out = Vec::new();
188	
189	    // HS folds surplus args of an arity-1 function into a pair at PARSE time
190	    // (`naryOpApp` `k == 1`, Theory/Text/Parser/Term.hs:84-87), so the AST the
191	    // wf check inspects already carries `h(<a, b>)` (an irreducible `h/1`
192	    // applied to a pair), NOT `h(a, b)`.  RS's arity-unaware parser keeps the
193	    // surplus args, so without this fold a unary `h(a, b)` resolves to a
194	    // non-existent reducible `h/2` and is spuriously flagged "uses terms of
195	    // the wrong form: reducible function symbols are disallowed".  Fold first
196	    // (mirrors the lemma/restriction pretty-printer in pretty_theory.rs).
197	    let arity1 = crate::elaborate::arity1_noeq_names(sig);
198	
199	    // HS `annFormulas = lemmas <|> restrictions` — all lemmas (theory
200	    // order) then all restrictions (theory order).
201	    let mut lemmas: Vec<(String, Formula)> = Vec::new();
202	    let mut restrictions: Vec<(String, Formula)> = Vec::new();
203	    for item in &thy.items {
204	        match item {
205	            p::TheoryItem::Lemma(l) => lemmas.push((
206	                format!("Lemma `{}'", l.name),
207	                crate::elaborate::rewrite_arity1_formula(&l.formula, &arity1))),
208	            p::TheoryItem::Restriction(r) | p::TheoryItem::LegacyAxiom(r) =>
209	                restrictions.push((
210	                    format!("Restriction `{}'", r.name),
211	                    crate::elaborate::rewrite_arity1_formula(&r.formula, &arity1))),
212	            _ => {}
213	        }
214	    }
215	    for (header, fm) in lemmas.into_iter().chain(restrictions) {
216	        if let Some(msg) = check_one(&header, &fm, &irr) {
217	            out.push(WfError::new("Formula terms", msg));
218	        }
219	    }
220	    out
221	}
222	
223	/// Run `checkTerms` for a single annotated formula.  Returns the formatted
224	/// WF block (matching HS byte-for-byte) iff there are offenders.
225	fn check_one(header: &str, fm: &Formula, irr: &Irreducible) -> Option<String> {
226	    let mut terms: Vec<RTerm> = Vec::new();
227	    collect_formula_terms(fm, &mut Vec::new(), irr, &mut terms);
228	
229	    let offenders: Vec<String> = terms
230	        .iter()
231	        .filter(|t| !allowed(t))
232	        .map(show_rterm)
233	        .collect();
234	
235	    if offenders.is_empty() {
236	        return None;
237	    }
238	    Some(render_block(header, &offenders))
239	}
240	
241	// =============================================================================
242	// formulaTerms / atomTerms with De-Bruijn assignment
243	// =============================================================================
244	
245	/// A binder in scope, tracked for De-Bruijn assignment.  `scope[0]` is the
246	/// OUTERMOST binder; `scope[last]` the innermost.  The De-Bruijn index of a
247	/// binder at position `i` is `scope.len() - 1 - i` (count of binders inner
248	/// to it).
249	type Scope = Vec<VarSpec>;
250	
251	/// HS `formulaTerms`: collect the terms from every atom.  Recurses through
252	/// connectives and quantifiers, pushing binders onto `scope` so that
253	/// variable uses inside the body get the right De-Bruijn index.
254	fn collect_formula_terms(
255	    fm: &Formula,
256	    scope: &mut Scope,
257	    irr: &Irreducible,
258	    out: &mut Vec<RTerm>,
259	) {
260	    match fm {
261	        Formula::True | Formula::False => {}
262	        Formula::Atom(a) => collect_atom_terms(a, scope, irr, out),
263	        Formula::Not(g) => collect_formula_terms(g, scope, irr, out),
264	        Formula::And(a, b)
265	        | Formula::Or(a, b)
266	        | Formula::Implies(a, b)
267	        | Formula::Iff(a, b) => {
268	            collect_formula_terms(a, scope, irr, out);
269	            collect_formula_terms(b, scope, irr, out);
270	        }
271	        Formula::Forall(vs, body) | Formula::Exists(vs, body) => {
272	            // HS `foldr (hinted q) f vs` quantifies the LAST var innermost.
273	            // Pushing in source order makes the last-listed var the
274	            // innermost binder (highest scope position) — exactly the
275	            // De-Bruijn nesting HS produces.
276	            let pushed = vs.len();
277	            for v in vs {
278	                scope.push(v.clone());
279	            }
280	            collect_formula_terms(body, scope, irr, out);
281	            for _ in 0..pushed {
282	                scope.pop();
283	            }
284	        }
285	    }
286	}
287	
288	/// HS `atomTerms` — the terms a single atom contributes.
289	fn collect_atom_terms(a: &Atom, scope: &Scope, irr: &Irreducible, out: &mut Vec<RTerm>) {
290	    match a {
291	        // Action i fa  ->  i : factTerms fa   (temporal var THEN fact args)
292	        Atom::Action(fact, tp) => {
293	            out.push(resolve_term(tp, scope, irr, TermPos::Temporal));
294	            for arg in &fact.args {
295	                out.push(resolve_term(arg, scope, irr, TermPos::Message));
296	            }
297	        }
298	        // EqE t s -> [t, s]
299	        Atom::Eq(x, y) => {
300	            out.push(resolve_term(x, scope, irr, TermPos::Message));
301	            out.push(resolve_term(y, scope, irr, TermPos::Message));
302	        }
303	        // Subterm i j -> [i, j]
304	        Atom::Subterm(x, y) => {
305	            out.push(resolve_term(x, scope, irr, TermPos::Message));
306	            out.push(resolve_term(y, scope, irr, TermPos::Message));
307	        }
308	        // Less i j -> [i, j]  (temporal node vars)
309	        Atom::Less(x, y) => {
310	            out.push(resolve_term(x, scope, irr, TermPos::Temporal));
311	            out.push(resolve_term(y, scope, irr, TermPos::Temporal));
312	        }
313	        // The multiset-`(<)` ordering relation: operands are message terms.
314	        Atom::LessMset(x, y) => {
315	            out.push(resolve_term(x, scope, irr, TermPos::Message));
316	            out.push(resolve_term(y, scope, irr, TermPos::Message));
317	        }
318	        // Last i -> [i]  (temporal)
319	        Atom::Last(tp) => {
320	            out.push(resolve_term(tp, scope, irr, TermPos::Temporal));
321	        }
322	        // Syntactic (predicate) atoms contribute no real terms
323	        // (HS `atomTerms (Syntactic _) = []`).
324	        Atom::Pred(_) => {}
325	    }
326	}
327	
328	/// The syntactic position of a term, which fixes the implicit sort of an
329	/// untagged variable use (mirrors the parser's positional sort inference).
330	#[derive(Clone, Copy, PartialEq)]
331	enum TermPos {
332	    /// Argument of `@`, `<`, `last` — implicitly a node (temporal) var.
333	    Temporal,
334	    /// A message-position term (fact arg, equality operand, ...).
335	    Message,
336	}
337	
338	// =============================================================================
339	// Term resolution: parser AST -> RTerm (with De-Bruijn + signature lookup)
340	// =============================================================================
341	
342	fn resolve_term(t: &Term, scope: &Scope, irr: &Irreducible, pos: TermPos) -> RTerm {
343	    match t {
344	        Term::Var(v) => resolve_var(v, scope, irr, pos),
345	        Term::PubLit(s) => RTerm::PubConst(s.clone()),
346	        Term::FreshLit(s) => RTerm::FreshConst(s.clone()),
347	        Term::NatLit(s) => RTerm::NatConst(s.clone()),
348	        // Bare numeric/`1`/`%1` literals: HS treats these as nullary
349	        // irreducible Public constructors.  The DH `1` is `oneSymString =
350	        // "one"` and the nat `%1` is `natOneSymString = "tone"`
351	        // (FunctionSymbols.hs:134,144); both are arity-0 Public Constructors
352	        // and hence always `allowed`, so the head name is never rendered as
353	        // an offender — but we still use the HS-faithful names here.
354	        Term::Number(n) => RTerm::PubConst(n.to_string()),
355	        Term::NumberOne => RTerm::App(Head::App { name: "one".into(), reducible: false }, vec![]),
356	        Term::NatOne => RTerm::App(Head::App { name: "tone".into(), reducible: false }, vec![]),
357	        Term::DhNeutral => RTerm::App(Head::App { name: "DH_neutral".into(), reducible: false }, vec![]),
358	        Term::App(name, args) => resolve_app(name, args, scope, irr),
359	        Term::AlgApp(name, a, b) => {
360	            // `op{a}b` == `op(a, b)`.
361	            let args = vec![
362	                resolve_term(a, scope, irr, TermPos::Message),
363	                resolve_term(b, scope, irr, TermPos::Message),
364	            ];
365	            resolve_named(name, args, irr)
366	        }
367	        Term::Pair(items) => {
368	            // `<a, b, c>` is right-nested `pair(a, pair(b, c))`.
369	            let resolved: Vec<RTerm> = items
370	                .iter()
371	                .map(|i| resolve_term(i, scope, irr, TermPos::Message))
372	                .collect();
373	            build_pair(resolved, irr)
374	        }
375	        Term::Diff(a, b) => {
376	            let args = vec![
377	                resolve_term(a, scope, irr, TermPos::Message),
378	                resolve_term(b, scope, irr, TermPos::Message),
379	            ];
380	            resolve_named("diff", args, irr)
381	        }
382	        Term::BinOp(op, a, b) => {
383	            let ra = resolve_term(a, scope, irr, TermPos::Message);
384	            let rb = resolve_term(b, scope, irr, TermPos::Message);
385	            match op {
386	                // `^` (exp) is a NoEq symbol; the rest are AC symbols.
387	                BinOp::Exp => resolve_named("exp", vec![ra, rb], irr),
388	                BinOp::Union => resolve_ac(AcSym::Union, vec![ra, rb], irr),
389	                BinOp::Mult => resolve_ac(AcSym::Mult, vec![ra, rb], irr),
390	                BinOp::Xor => resolve_ac(AcSym::Xor, vec![ra, rb], irr),
391	                BinOp::NatPlus => resolve_ac(AcSym::NatPlus, vec![ra, rb], irr),
392	            }
393	        }
394	        Term::PatMatch(inner) => resolve_term(inner, scope, irr, pos),
395	    }
396	}
