398	fn resolve_app(name: &str, args: &[Term], scope: &Scope, irr: &Irreducible) -> RTerm {
399	    let resolved: Vec<RTerm> = args
400	        .iter()
401	        .map(|a| resolve_term(a, scope, irr, TermPos::Message))
402	        .collect();
403	    resolve_named(name, resolved, irr)
404	}
