414	/// Build an AC application node, classifying via the irreducible AC set.
415	/// Union is HS-special-cased (`FUnion` — always allowed-if-args-allowed)
416	/// so we force `reducible = false` for it regardless of set membership.
417	fn resolve_ac(sym: AcSym, args: Vec<RTerm>, irr: &Irreducible) -> RTerm {
418	    let reducible = if matches!(sym, AcSym::Union) {
419	        false
420	    } else {
421	        !irr.is_ac_irreducible(sym)
422	    };
423	    RTerm::App(Head::Ac { sym, reducible }, args)
424	}
