426	/// Right-nested pair construction matching HS's `<a,b,c> = pair(a, pair(b,
427	/// c))`.  `pair` is irreducible.
428	fn build_pair(mut items: Vec<RTerm>, irr: &Irreducible) -> RTerm {
429	    if items.is_empty() {
430	        return resolve_named("pair", vec![], irr);
431	    }
432	    if items.len() == 1 {
433	        return items.pop().unwrap();
434	    }
435	    let head = items.remove(0);
436	    let rest = build_pair(items, irr);
437	    resolve_named("pair", vec![head, rest], irr)
438	}
