440	/// Resolve a variable USE to either a `Bound n` (if a matching binder is in
441	/// scope) or `Free` (otherwise) — UNLESS the name is a declared nullary
442	/// function symbol with no matching binder, in which case it is an
443	/// irreducible `FApp name []` (HS resolves `f/0` to `FApp f []`).
444	fn resolve_var(v: &VarSpec, scope: &Scope, irr: &Irreducible, pos: TermPos) -> RTerm {
445	    if let Some(idx) = lookup_bound(v, scope, pos) {
446	        return RTerm::Bound(idx);
447	    }
448	    // Not bound: a bare untagged name that is a declared nullary funsym
449	    // is an application (e.g. private `f/0` parsed as Var("f")).
450	    if matches!(v.sort, SortHint::Untagged) && irr.nullary_named(&v.name) {
451	        return resolve_named(&v.name, vec![], irr);
452	    }
453	    RTerm::Free(v.clone())
454	}
