456	/// Find the innermost binder matching `v` and return its De-Bruijn index.
457	///
458	/// HS binds a use to its binder via full `LVar` equality — name AND sort AND
459	/// idx (`quantify x = ... | v == x = Bound i`, Formula.hs:340-345; `LVar` `Eq`
460	/// compares `idx`, sort and name, LTerm.hs:516-517). We reproduce this exactly
461	/// on the sort-*kind*: the use's sort is concrete in HS, never approximate.
462	/// The parser assigns every variable a concrete `LSort` before `quantify`
463	/// runs (Formula.hs:114 `standardFormula msgvar nodevar`):
464	///   - a message-position variable is parsed by `msgvar`
465	///     (`sortedLVar [LSortFresh, LSortPub, LSortNat, LSortMsg]`,
466	///     Token.hs:440-441), so an *untagged* message use takes the
467	///     `mkPrefixParser LSortMsg` arm (the bare `LSortMsg -> pure ()` case,
468	///     Token.hs:424-426) and gets the concrete sort `LSortMsg` — hence
469	///     `kind_of(SortHint::Untagged) == KIND_MSG` is exact, not approximate;
470	///   - a temporal-position variable is parsed by `nodevar`
471	///     (`LSortNode`, Token.hs:444-447), hence `KIND_NODE`.
472	///
473	/// `quantify`'s `v == x` then compares sort exactly, so an untagged `x` binds
474	/// only to a `LSortMsg` binder, never to a `~x`/`$x`/`%x`/`#x` binder of the
475	/// same name+idx. The `idx` comparison likewise keeps `x.1` and `x.2` distinct.
476	fn lookup_bound(v: &VarSpec, scope: &Scope, pos: TermPos) -> Option<u32> {
477	    // The use's concrete sort-kind (Temporal positions are LSortNode; message
478	    // positions take the use's sigil, or LSortMsg when untagged — see above).
479	    let expected: u8 = match pos {
480	        TermPos::Temporal => KIND_NODE,
481	        TermPos::Message => kind_of(&v.sort),
482	    };
483	    // Search innermost (last) first.
484	    for (i, b) in scope.iter().enumerate().rev() {
485	        if b.name != v.name || b.idx != v.idx {
486	            continue;
487	        }
488	        if kind_of(&b.sort) == expected {
489	            let db = (scope.len() - 1 - i) as u32;
490	            return Some(db);
491	        }
492	    }
493	    None
494	}
495	
496	const KIND_FRESH: u8 = 0;
497	const KIND_PUB: u8 = 1;
498	const KIND_NODE: u8 = 2;
499	const KIND_NAT: u8 = 3;
500	const KIND_MSG: u8 = 4;
501	
502	fn kind_of(s: &SortHint) -> u8 {
503	    match s {
504	        SortHint::Fresh | SortHint::Suffix(SuffixSort::Fresh) => KIND_FRESH,
505	        SortHint::Pub | SortHint::Suffix(SuffixSort::Pub) => KIND_PUB,
506	        SortHint::Node | SortHint::Suffix(SuffixSort::Node) => KIND_NODE,
507	        SortHint::Nat | SortHint::Suffix(SuffixSort::Nat) => KIND_NAT,
508	        SortHint::Msg | SortHint::Suffix(SuffixSort::Msg) => KIND_MSG,
509	        SortHint::Untagged => KIND_MSG,
510	    }
511	}
