514	// `allowed` predicate (HS Wellformedness.hs:978-985)
515	// =============================================================================
516	
517	fn allowed(t: &RTerm) -> bool {
518	    match t {
519	        RTerm::Bound(_) => true,
520	        RTerm::PubConst(_) => true,
521	        RTerm::App(Head::App { reducible, .. }, args)
522	        | RTerm::App(Head::Ac { reducible, .. }, args) => {
523	            !*reducible && args.iter().all(allowed)
524	        }
525	        // Free vars, fresh/nat name constants -> offenders.
526	        RTerm::Free(_) | RTerm::FreshConst(_) | RTerm::NatConst(_) => false,
527	    }
528	}
