531	// `show` of an offender term (HS `Show (VTerm Name (BVar LVar))`)
532	// =============================================================================
533	
534	fn show_rterm(t: &RTerm) -> String {
535	    let mut s = String::new();
536	    write_rterm(t, &mut s);
537	    s
538	}
