540	fn write_rterm(t: &RTerm, out: &mut String) {
541	    match t {
542	        RTerm::Bound(n) => {
543	            out.push_str("Bound ");
544	            out.push_str(&n.to_string());
545	        }
546	        RTerm::Free(v) => {
547	            out.push_str("Free ");
548	            out.push_str(&show_lvar(v));
549	        }
550	        // HS `Show Name`: PubName -> `'n'`, FreshName -> `~'n'`,
551	        // NatName -> `%'n'`.
552	        RTerm::PubConst(n) => {
553	            out.push('\'');
554	            out.push_str(n);
555	            out.push('\'');
556	        }
557	        RTerm::FreshConst(n) => {
558	            out.push_str("~'");
559	            out.push_str(n);
560	            out.push('\'');
561	        }
562	        RTerm::NatConst(n) => {
563	            out.push_str("%'");
564	            out.push_str(n);
565	            out.push('\'');
566	        }
567	        RTerm::App(head, args) => {
568	            // HS `Show (Term a)` (Term/Raw.hs:219-227):
569	            //   FApp (NoEq (s,_)) [] -> s
570	            //   FApp (NoEq (s,_)) as -> s ++ "(" ++ intercalate "," ... ++ ")"
571	            //   FApp (AC o) as       -> show o ++ "(" ++ ... ++ ")"
572	            // ACSym derives Show as the constructor name (Union/Mult/Xor/NatPlus).
573	            let name: &str = match head {
574	                Head::App { name, .. } => name.as_str(),
575	                Head::Ac { sym, .. } => match sym {
576	                    AcSym::Union => "Union",
577	                    AcSym::Mult => "Mult",
578	                    AcSym::Xor => "Xor",
579	                    AcSym::NatPlus => "NatPlus",
580	                },
581	            };
582	            out.push_str(name);
583	            if !args.is_empty() {
584	                out.push('(');
585	                for (i, a) in args.iter().enumerate() {
586	                    if i > 0 {
587	                        out.push(',');
588	                    }
589	                    write_rterm(a, out);
590	                }
591	                out.push(')');
592	            }
593	        }
594	    }
595	}
