597	/// HS `Show LVar`: `sortPrefix s ++ body`, where body is the name (or, if
598	/// `idx /= 0`, `name.idx`; if the name is empty, just the index).
599	/// Shared with the message-derivation probe (`deriv_check`).
600	pub(crate) fn show_lvar(v: &VarSpec) -> String {
601	    let prefix = match v.sort {
602	        SortHint::Fresh | SortHint::Suffix(SuffixSort::Fresh) => "~",
603	        SortHint::Pub | SortHint::Suffix(SuffixSort::Pub) => "$",
604	        SortHint::Node | SortHint::Suffix(SuffixSort::Node) => "#",
605	        SortHint::Nat | SortHint::Suffix(SuffixSort::Nat) => "%",
606	        _ => "",
607	    };
608	    let body = if v.name.is_empty() {
609	        v.idx.to_string()
610	    } else if v.idx == 0 {
611	        v.name.clone()
612	    } else {
613	        format!("{}.{}", v.name, v.idx)
614	    };
615	    format!("{}{}", prefix, body)
616	}
