622	/// Build the full "Formula terms" topic block (underline header + offender
623	/// fsep line + blank `$--$` line + wrapped paragraph), byte-identical to HS.
624	fn render_block(header: &str, offenders: &[String]) -> String {
625	    // fsep $ (text "<header> uses terms of the wrong form:")
626	    //       : punctuate comma (map (nest 2 . text . quote . show) offenders)
627	    let mut items = vec![Doc::text(format!("{} uses terms of the wrong form:", header))];
628	    let off_docs: Vec<Doc> = offenders
629	        .iter()
630	        .map(|o| Doc::text(format!("`{}'", o)).nest(2))
631	        .collect();
632	    items.extend(punctuate(Doc::text(","), off_docs));
633	    let line1 = fsep(items).nest(2).render_with(WF_WIDTH, WF_WIDTH);
634	
635	    let words: Vec<Doc> = ALLOWED_PARAGRAPH.split_whitespace().map(Doc::text).collect();
636	    let para = fsep(words).nest(2).render_with(WF_WIDTH, WF_WIDTH);
637	
638	    let mut out = String::new();
639	    out.push_str("Formula terms\n=============\n");
640	    out.push('\n'); // HS `$-$` blank line before the nest-2 body
641	    out.push_str(&line1);
642	    out.push('\n');
643	    out.push_str("  \n"); // HS `$--$` blank line (nest-2 `text ""`)
644	    out.push_str(&para);
645	    out
646	}
