1180	/// comma. Matches the oracle's wrapping at column 69 (probes r3_wrap/r3_w2).
1181	fn fill_after_prefix(prefix: &str, tokens: &[String], indent: usize, width: usize) -> String {
1182	    let mut line = prefix.to_string();
1183	    let mut col = prefix.chars().count();
1184	    let pad = " ".repeat(indent);
1185	    let n = tokens.len();
1186	    for (i, tok) in tokens.iter().enumerate() {
1187	        let piece = if i + 1 < n {
1188	            format!("{},", tok)
1189	        } else {
1190	            tok.clone()
1191	        };
1192	        let w = piece.chars().count();
1193	        if col + 1 + w <= width {
1194	            line.push(' ');
1195	            line.push_str(&piece);
1196	            col += 1 + w;
1197	        } else {
1198	            line.push('\n');
1199	            line.push_str(&pad);
1200	            line.push_str(&piece);
1201	            col = indent + w;
1202	        }
1203	    }
1204	    line
1205	}
