1242	// ---------------------------------------------------------------------------
1243	// Formula guardedness (decision procedure over the guarded fragment)
1244	// ---------------------------------------------------------------------------
1245	// A LEMMA formula must be convertible to guarded form (an unguarded RESTRICTION
1246	// is a fatal error, not a warning, so this check is lemma-only). A universal is
1247	// guarded only as `guard ==> rest`; an existential as a conjunction whose action
1248	// atoms guard its variables. The guard of a quantifier is the set of variables
1249	// occurring in ACTION atoms reachable through conjunctions of the antecedent
1250	// (universal) or body (existential); disjunction, negation, implication,
1251	// equality/ordering atoms and nested quantifiers contribute no guards. The first
1252	// failing quantifier (antecedent before consequent, left before right) is
1253	// reported together with the whole lemma formula.
1254	
1255	/// A guardedness failure and its reason.
1256	enum GuardFail {
1257	    /// A quantifier binds variables not guarded by an action atom.
1258	    Unguarded(Vec<VarSpec>),
1259	    /// A universal quantifier's body is not a top-level implication.
1260	    NoImplication,
1261	}
1262	
1263	/// Collect the variables of every ACTION atom reachable through conjunctions of
1264	/// `f`. These are the variables a guard binds.
1265	fn collect_guard_vars(f: &Formula, out: &mut Vec<VarSpec>) {
1266	    match f {
1267	        Formula::Atom(Atom::Action(fact, t)) => {
1268	            collect_fact_vars(fact, out);
1269	            collect_term_vars(t, out);
1270	        }
1271	        Formula::And(a, b) => {
1272	            collect_guard_vars(a, out);
1273	            collect_guard_vars(b, out);
1274	        }
1275	        _ => {}
1276	    }
1277	}
1278	
1279	/// The `(name, class)` keys of a guard formula's action-atom variables.
1280	fn guard_key_set(f: &Formula) -> std::collections::HashSet<(String, SortClass)> {
1281	    let mut gv = Vec::new();
1282	    collect_guard_vars(f, &mut gv);
1283	    gv.iter().map(|v| (v.name.clone(), var_class(v))).collect()
1284	}
1285	
1286	/// Quantified variables of `vs` not guarded by `gset` (matched sort-aware), in
1287	/// binding order.
1288	fn unguarded_vars(
1289	    vs: &[VarSpec],
1290	    gset: &std::collections::HashSet<(String, SortClass)>,
1291	) -> Vec<VarSpec> {
1292	    vs.iter()
1293	        .filter(|v| !gset.contains(&(v.name.clone(), var_class(v))))
1294	        .cloned()
1295	        .collect()
1296	}
1297	
1298	/// Return the first guardedness failure and the failing quantifier subformula.
1299	fn find_guard_failure(f: &Formula) -> Option<(GuardFail, Formula)> {
1300	    match f {
1301	        Formula::Forall(vs, body) => match &**body {
1302	            Formula::Implies(guard, rest) => {
1303	                let unguarded = unguarded_vars(vs, &guard_key_set(guard));
1304	                if !unguarded.is_empty() {
1305	                    return Some((GuardFail::Unguarded(unguarded), f.clone()));
1306	                }
1307	                find_guard_failure(guard).or_else(|| find_guard_failure(rest))
1308	            }
1309	            _ => Some((GuardFail::NoImplication, f.clone())),
1310	        },
1311	        Formula::Exists(vs, body) => {
1312	            let unguarded = unguarded_vars(vs, &guard_key_set(body));
1313	            if !unguarded.is_empty() {
1314	                return Some((GuardFail::Unguarded(unguarded), f.clone()));
1315	            }
1316	            find_guard_failure(body)
1317	        }
1318	        Formula::Not(g) => find_guard_failure(g),
1319	        Formula::And(a, b)
1320	        | Formula::Or(a, b)
1321	        | Formula::Implies(a, b)
1322	        | Formula::Iff(a, b) => find_guard_failure(a).or_else(|| find_guard_failure(b)),
1323	        _ => None,
1324	    }
1325	}
