1327	/// The guardedness report entry for one lemma, or `None` when it is guarded.
1328	fn guardedness_entry(name: &str, f: &Formula) -> Option<String> {
1329	    let (fail, sub) = find_guard_failure(f)?;
1330	    let reason = match fail {
1331	        GuardFail::Unguarded(vars) => {
1332	            let vs: Vec<String> = vars.iter().map(|v| format!("'{}'", pp_var(v))).collect();
1333	            format!("unguarded variable(s) {} in the subformula", vs.join(", "))
1334	        }
1335	        GuardFail::NoImplication => {
1336	            "universal quantifier without toplevel implication".to_string()
1337	        }
1338	    };
1339	    // The formula is embedded as `      "..."`: its first character sits at
1340	    // column 7 (after six spaces and the quote).
1341	    let pp_sub = crate::formula::pp_formula_wrapped(&sub, 7);
1342	    let pp_whole = crate::formula::pp_formula_wrapped(f, 7);
1343	    Some(format!(
1344	        "  Lemma `{}' cannot be converted to a guarded formula:\n    {}\n      \"{}\"\n    in the formula\n      \"{}\"",
1345	        name, reason, pp_sub, pp_whole
1346	    ))
1347	}
