1394	/// Merge a sequence of `(topic, entry)` pairs, joining only CONSECUTIVE
1395	/// same-topic entries (separator `"\n  \n"`) into one `WfError` block.
1396	fn merge_consecutive(seq: Vec<(&'static str, String)>) -> Vec<WfError> {
1397	    let mut out: Vec<WfError> = Vec::new();
1398	    for (topic, entry) in seq {
1399	        if let Some(last) = out.last_mut() {
1400	            if last.topic == topic {
1401	                last.message.push_str("\n  \n");
1402	                last.message.push_str(&entry);
1403	                continue;
1404	            }
1405	        }
1406	        out.push(WfError::new(topic, entry));
1407	    }
1408	    out
1409	}
