36	        let mut parts = lhs.split_whitespace();
37	        let name = parts.next().expect("fixture name");
38	        let mut is_diff = false;
39	        for f in parts { if f == "--diff" { is_diff = true; } }
40	        let expected_topics: BTreeSet<String> = rhs
41	            .split(',')
42	            .map(|s| s.trim().to_string())
43	            .filter(|s| !s.is_empty())
44	            .collect();
45	        out.push(Fixture {
