54	#[test]
55	fn every_fixture_parses_and_matches() {
56	    let fixtures = load_fixtures();
57	    assert!(!fixtures.is_empty(), "no fixtures loaded");
58	    let dir = fixtures_dir();
59	    let mut failures = Vec::new();
60	    for fx in &fixtures {
61	        let path = dir.join(format!("{}.spthy", fx.name));
62	        let src = fs::read_to_string(&path)
63	            .unwrap_or_else(|_| panic!("missing fixture file: {}", path.display()));
64	        let mut thy = match parse_theory(&src, &["diff"]) {
65	            Ok(t) => t,
66	            Err(e) => {
67	                failures.push(format!("PARSE  {}: {}", fx.name, e));
68	                continue;
69	            }
70	        };
71	        if fx.is_diff { thy.is_diff = true; }
72	        // Normalise trailing whitespace: some HS wellformedness titles
73	        // carry a source-literal trailing space (e.g.
74	        // "...not in any right-hand-side "), which the comma-separated
75	        // `expected.txt` cannot represent because its entries are
76	        // `.trim()`-ed when parsed.  Compare titles modulo trailing space.
77	        let topics: BTreeSet<String> = wf::topics(&wf::check_theory(&thy))
78	            .into_iter()
79	            .map(|s| s.trim_end().to_string())
80	            .collect();
81	        // The "Formula terms" check (HS `checkTerms`) needs the elaborated
82	        // `MaudeSig` for reducible/irreducible funsym classification, so it
83	        // lives in `tamarin_theory::check_terms` and runs post-elaboration
84	        // (wired in `tamarin-prover`'s `run.rs`) — NOT in the parser-level
85	        // `check_theory`.  It is covered by `check_terms`'s own unit tests
86	        // and the corpus raw-diff sweep.  Drop it from this parser-only
87	        // comparison so the fixtures that exercise it aren't spuriously
88	        // failed here.
89	        let mut expected = fx.expected.clone();
90	        expected.remove("Formula terms");
91	        if !expected.is_subset(&topics) {
92	            let missing: Vec<_> = expected.difference(&topics).collect();
93	            failures.push(format!(
94	                "TOPIC  {}: missing {:?} (got {:?})", fx.name, missing, topics));
95	        }
96	    }
97	    assert!(failures.is_empty(), "{}", failures.join("\n"));
98	}
