1	//! Run the wellformedness fixture corpus against:
2	//!
3	//!   1. Our parser — every fixture must parse without error.
4	//!   2. Our Rust wellformedness checker — the topics it emits must
5	//!      include every expected topic from `expected.txt`.
6	//!   3. Tamarin (binary) — the expected topics must also be a subset of
7	//!      what `tamarin-prover` actually emits, confirming we're shooting
8	//!      at the right targets.
9	//!
10	//! Usage:  cargo run -p tamarin-parser --example wellformedness_fixtures \
11	//!           [-- <fixtures-dir>]
12	//!
13	//! Pass `--no-tamarin` to skip the Tamarin oracle pass (e.g. on systems
14	//! without the binary installed).
15	
16	// Example/dev tool: prints fixture results to stdout by design; allow the
17	// `disallowed_macros` convention freeze for this example binary.
18	#![allow(clippy::disallowed_macros)]
19	
20	use std::collections::BTreeSet;
21	use std::env;
22	use std::fs;
23	use std::path::PathBuf;
24	
25	use tamarin_parser::{parse_theory, wf};
26	
27	mod common;
28	use common::run_tamarin;
29	
30	fn main() {
31	    let args = env::args().skip(1);
32	    let mut dir = PathBuf::from(env!("CARGO_MANIFEST_DIR"))
33	        .parent().unwrap()
34	        .parent().unwrap()
35	        .join("tests")
36	        .join("wellformedness_fixtures");
37	    let mut run_tamarin_oracle = true;
38	    let mut positional: Vec<String> = Vec::new();
39	    for a in args {
40	        match a.as_str() {
41	            "--no-tamarin" => run_tamarin_oracle = false,
42	            other => positional.push(other.to_string()),
43	        }
44	    }
45	    if let Some(a) = positional.into_iter().next() { dir = PathBuf::from(a); }
46	    let tamarin = env::var("TAMARIN").unwrap_or_else(|_| "tamarin-prover".into());
47	
48	    let expected_path = dir.join("expected.txt");
49	    let expected = fs::read_to_string(&expected_path)
50	        .unwrap_or_else(|_| panic!("missing expected.txt at {}", expected_path.display()));
51	
52	    let mut total = 0usize;
53	    let mut parser_ok = 0usize;
54	    let mut rust_wf_match = 0usize;
55	    let mut topics_match = 0usize;
56	    let mut fail_lines: Vec<String> = Vec::new();
57	
58	    for line in expected.lines() {
59	        let line = line.trim();
60	        if line.is_empty() || line.starts_with('#') { continue; }
61	        let (lhs, rhs) = match line.split_once(':') { Some(p) => p, None => continue };
62	        let mut parts = lhs.split_whitespace();
63	        let name = match parts.next() { Some(n) => n, None => continue };
64	        let mut flags: Vec<String> = Vec::new();
65	        for f in parts { flags.push(f.to_string()); }
66	        let expected_topics: BTreeSet<String> = rhs
67	            .split(',')
68	            .map(|s| s.trim().to_string())
69	            .filter(|s| !s.is_empty())
70	            .collect();
71	
72	        total += 1;
73	
74	        let path = dir.join(format!("{}.spthy", name));
75	        let src = fs::read_to_string(&path).unwrap_or_else(|_| panic!("missing {}", path.display()));
76	
77	        // 1. Our parser must accept the fixture.
78	        let mut thy = match parse_theory(&src, &["diff"]) {
79	            Ok(t) => { parser_ok += 1; t }
80	            Err(e) => {
81	                fail_lines.push(format!("PARSE  {}: {}", name, e));
82	                continue;
83	            }
84	        };
85	        // Override is_diff if the fixture is flagged --diff. Our parser
86	        // doesn't auto-detect diff mode (Tamarin uses a separate
87	        // entry point), so we surface it from the fixture metadata.
88	        if flags.iter().any(|f| f == "--diff") { thy.is_diff = true; }
89	
90	        // 2. Our Rust wf checker must emit every expected topic. Same
91	        // comparison semantics as tests/wellformedness.rs: titles compare
92	        // modulo trailing space (some HS titles carry a source-literal
93	        // trailing space that comma-separated expected.txt cannot hold),
94	        // and "Formula terms" (HS `checkTerms`) is excluded — it needs the
95	        // elaborated MaudeSig, so it lives in `tamarin_theory::check_terms`
96	        // post-elaboration rather than the parser-level `check_theory`;
97	        // step 3 still verifies it against the tamarin binary.
98	        let rust_topics: BTreeSet<String> = wf::topics(&wf::check_theory(&thy))
99	            .into_iter()
100	            .map(|s| s.trim_end().to_string())
101	            .collect();
102	        let mut rust_expected = expected_topics.clone();
103	        rust_expected.remove("Formula terms");
104	        if rust_expected.is_subset(&rust_topics) {
105	            rust_wf_match += 1;
106	        } else {
107	            let missing: Vec<_> = rust_expected.difference(&rust_topics).collect();
108	            fail_lines.push(format!(
109	                "RUST   {}: missing {:?} (got: {:?})", name, missing, rust_topics));
110	        }
111	
112	        // 3. (Optional) Tamarin must emit the expected topics.
113	        if run_tamarin_oracle {
114	            let actual = run_tamarin(&tamarin, &path, &flags).unwrap_or_default();
115	            if expected_topics.is_subset(&actual) {
116	                topics_match += 1;
117	            } else {
118	                let missing: Vec<_> = expected_topics.difference(&actual).collect();
119	                fail_lines.push(format!(
120	                    "TOPICS {}: missing {:?} (actual: {:?})", name, missing, actual));
121	            }
122	        }
123	    }
124	
125	    println!("Fixtures total:   {}", total);
126	    println!("Parsed OK:        {} ({:.0}%)",
127	        parser_ok, 100.0 * parser_ok as f64 / total.max(1) as f64);
128	    println!("Rust wf match:    {} ({:.0}%)",
129	        rust_wf_match, 100.0 * rust_wf_match as f64 / total.max(1) as f64);
130	    if run_tamarin_oracle {
131	        println!("Tamarin match:    {} ({:.0}%)",
132	            topics_match, 100.0 * topics_match as f64 / total.max(1) as f64);
133	    }
134	    if !fail_lines.is_empty() {
135	        println!("\nFailures:");
136	        for l in fail_lines { println!("  {}", l); }
137	        std::process::exit(1);
138	    }
139	}
