//! Workspace-authored integration adapters bridging the elaborated
//! [`MaudeSig`] to the parser-level wellformedness checker
//! (`tamarin_parser::wf`).
//!
//! The clean `formula_terms` / `formula_reports` checks classify a function
//! application as ill-formed when its head symbol name is in a caller-supplied
//! reducible-symbol set. The surface parser has no signature, so the set is
//! derived here from the elaborated signature and handed to the check.

use std::collections::BTreeSet;

use tamarin_term::function_symbols::FunSym;
use tamarin_term::maude_sig::MaudeSig;

/// Names of the reducible function symbols in `sig` — every declared function
/// symbol that is not irreducible. The clean "Formula terms" check disallows an
/// application whose head name is in this set.
pub fn reducible_funsym_names(sig: &MaudeSig) -> BTreeSet<String> {
    sig.fun_syms
        .difference(&sig.irreducible_fun_syms)
        .filter_map(|s| match s {
            FunSym::NoEq(n) => Some(String::from_utf8_lossy(n.name).into_owned()),
            _ => None,
        })
        .collect()
}

