//! Byte-level coverage for the Formula-terms wellformedness check as routed
//! through the clean parser-level checker (`tamarin_parser::wf`) with the
//! reducible-symbol set supplied by `tamarin_theory::wf_adapt` from the
//! elaborated signature. This is the same wiring `run.rs` / `theory_io.rs` use,
//! and it preserves the captured cases the former ported `check_terms` module
//! carried.

use std::collections::BTreeSet;

use tamarin_parser::{parse_theory, wf};
use tamarin_theory::wf_adapt::reducible_funsym_names;

/// Run the Formula-terms check exactly as the prover pipeline does: expand
/// macros, elaborate to get the reducible funsym set, then run the clean
/// `formula_terms_reducible`.
fn formula_terms(src: &str) -> Vec<wf::WfError> {
    let mut thy = parse_theory(src, &[]).expect("parse");
    tamarin_theory::macro_expand::expand_theory_macros(&mut thy);
    let elab = tamarin_theory::elaborate::elaborate(&thy).expect("elaborate");
    let reducible: BTreeSet<String> =
        reducible_funsym_names(&elab.signature.maude_sig);
    wf::formula_terms_reducible(&thy, &reducible)
}

#[test]
fn untagged_message_use_does_not_bind_to_node_binder() {
    // Captured node-binder case: an untagged message-position use `x` must NOT
    // bind to a `#x` node binder of the same name. Verified against the
    // v1.13.0 binary on `All #x. (K(x) @ #x) ==> F`, which prints
    // `Lemma `L' uses terms of the wrong form: `Free x'`.
    let report = formula_terms(
        "theory T begin\nlemma L:\n  \"All #x. (K(x) @ #x) ==> F\"\nend\n",
    );
    assert_eq!(report.len(), 1, "expected one Formula-terms block: {report:?}");
    assert!(
        report[0].message.contains("`Free x'"),
        "untagged use must stay Free (not bind to #x), got:\n{}",
        report[0].message
    );
}

#[test]
fn reducible_destructor_is_offender() {
    let report = formula_terms(
        "theory T begin\n\
         builtins: symmetric-encryption\n\
         lemma L:\n\
           \"All x #i. K(x) @ i ==> Ex body key #j #k. \
             K(body) @ j & key = snd(sdec(body, key)) & j < i & k < i\"\n\
         end\n",
    );
    assert_eq!(report.len(), 1, "expected one Formula-terms block");
    assert!(
        report[0].message.contains("snd(sdec(")
            && report[0].message.contains("uses terms of the wrong form"),
        "reducible destructor must be flagged, got:\n{}",
        report[0].message
    );
}

#[test]
fn plain_protocol_lemma_no_offenders() {
    assert!(formula_terms(
        "theory T begin\nlemma L:\n  \"All x #i. K(x) @ i ==> Ex #j. K(x) @ j\"\nend\n"
    )
    .is_empty());
}

#[test]
fn public_constant_allowed() {
    assert!(formula_terms(
        "theory T begin\nlemma L:\n  \"All #i. K('c') @ i ==> F\"\nend\n"
    )
    .is_empty());
}

#[test]
fn unary_hash_with_surplus_args_is_allowed() {
    // `hashing` gives `h/1`; `h` is irreducible so it is not in the reducible
    // set and `h(x, y)` is allowed (name-keyed reducibility sidesteps arity).
    assert!(formula_terms(
        "theory T begin\n\
         builtins: hashing\n\
         lemma L:\n  \"All x y #i. K(h(x, y)) @ i ==> F\"\nend\n"
    )
    .is_empty());
}

