pub fn reducible_funsym_names(sig: &MaudeSig) -> BTreeSet<String> {
    sig.fun_syms
        .difference(&sig.irreducible_fun_syms)
        .filter_map(|s| match s {
            FunSym::NoEq(n) => Some(String::from_utf8_lossy(n.name).into_owned()),
            _ => None,
        })
        .collect()
}

/// Give the node sort to every variable used in a temporal position — the
/// timepoint of an action atom, the operands of `<`, the argument of `last` —
/// that the surface parser left untagged.
///
/// A timepoint written without a `#` sigil (`... @ i`) parses as an untagged
/// variable; only the `#i` binder carries the node sort. The clean formula
/// checks bind a use to a quantifier by matching sort class, so an untagged
/// timepoint use would not bind to its `#i` binder. This fills the node sort in
/// for those positions (the temporal-position convention already used by the
/// guarded-formula conversion) so the checks see a fully sorted formula.
pub fn normalize_temporal_sorts(thy: &mut p::Theory) {
    for item in &mut thy.items {
        match item {
            p::TheoryItem::Lemma(l) => normalize_formula(&mut l.formula),
            p::TheoryItem::Restriction(r) | p::TheoryItem::LegacyAxiom(r) => {
                normalize_formula(&mut r.formula)
            }
            _ => {}
        }
    }
}

fn normalize_formula(f: &mut p::Formula) {
    match f {
        p::Formula::Atom(a) => normalize_atom(a),
        p::Formula::Not(g) => normalize_formula(g),
        p::Formula::And(a, b)
        | p::Formula::Or(a, b)
        | p::Formula::Implies(a, b)
        | p::Formula::Iff(a, b) => {
            normalize_formula(a);
            normalize_formula(b);
        }
        p::Formula::Forall(_, g) | p::Formula::Exists(_, g) => normalize_formula(g),
        p::Formula::True | p::Formula::False => {}
    }
}

fn normalize_atom(a: &mut p::Atom) {
    match a {
        p::Atom::Action(_, tp) | p::Atom::Last(tp) => set_node(tp),
        p::Atom::Less(x, y) => {
            set_node(x);
            set_node(y);
        }
        p::Atom::Eq(_, _)
        | p::Atom::LessMset(_, _)
        | p::Atom::Subterm(_, _)
        | p::Atom::Pred(_) => {}
    }
}

fn set_node(t: &mut p::Term) {
    if let p::Term::Var(v) = t {
        if matches!(v.sort, p::SortHint::Untagged) {
            v.sort = p::SortHint::Node;
        }
    }
}

